server/tests/test_presets.py :: test_list_presets_includes_web
def test_list_presets_includes_web() -> None:
    names = {preset["name"] for preset in list_presets()}
    assert "web" in names
    assert "email" in names
    assert "archive" in names

server/tests/test_presets.py :: test_get_preset_unknown_raises
def test_get_preset_unknown_raises() -> None:
    try:
        get_preset("not-a-real-preset")
    except ValueError as error:
        assert "Unknown preset" in str(error)
        return
    raise AssertionError("Expected ValueError")
